8	  :root {
9	    --bg: #0d1117; --panel: #161b22; --border: #30363d; --fg: #e6edf3;
10	    --muted: #8b949e; --accent: #2f81f7; --good: #3fb950; --warn: #d29922;
11	    --bad: #f85149; --chip: #21262d;
12	  }
13	  * { box-sizing: border-box; }
14	  body { margin: 0; font: 14px/1.5 -apple-system, "Segoe UI", Roboto, sans-serif;
15	    background: var(--bg); color: var(--fg); }
16	  header { display: flex; align-items: center; gap: 16px; padding: 12px 20px;
17	    border-bottom: 1px solid var(--border); background: var(--panel); position: sticky; top: 0; z-index: 5; }
18	  header h1 { font-size: 16px; margin: 0; font-weight: 600; }
19	  header .spacer { flex: 1; }
20	  .stat { font-size: 12px; color: var(--muted); }
21	  .stat b { color: var(--fg); font-size: 14px; }
22	  button { background: var(--accent); color: #fff; border: 0; border-radius: 6px;
23	    padding: 7px 12px; font-size: 13px; cursor: pointer; }
24	  button:hover { filter: brightness(1.1); }
25	  button.ghost { background: var(--chip); color: var(--fg); border: 1px solid var(--border); }
26	  .layout { display: grid; grid-template-columns: 280px 1fr 320px; gap: 0; height: calc(100vh - 53px); }
27	  .col { overflow-y: auto; padding: 14px; }
28	  .col.left { border-right: 1px solid var(--border); }
29	  .col.right { border-left: 1px solid var(--border); background: var(--panel); }
30	  h2 { font-size: 11px; text-transform: uppercase; letter-spacing: .06em; color: var(--muted);
31	    margin: 0 0 8px; font-weight: 600; }
32	  .section { margin-bottom: 22px; }
33	  .ent { padding: 7px 9px; border-radius: 6px; cursor: pointer; display: flex; justify-content: space-between;
34	    align-items: center; gap: 6px; }
35	  .ent:hover { background: var(--chip); }
36	  .ent.sel { background: #1f6feb33; outline: 1px solid var(--accent); }
37	  .ent .nm { overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
38	  .ent .ty { font-size: 10px; color: var(--muted); }
39	  .badge { font-size: 10px; padding: 1px 6px; border-radius: 10px; background: var(--chip);
40	    color: var(--muted); white-space: nowrap; }
41	  .badge.ready { color: var(--good); } .badge.seeded { color: var(--warn); }
42	  .mc { font-size: 11px; color: var(--accent); }
43	  .card { background: var(--panel); border: 1px solid var(--border); border-radius: 8px;
44	    padding: 14px; margin-bottom: 12px; }
45	  .match-head { display: flex; align-items: baseline; gap: 10px; }
46	  .match-head .score { font-size: 20px; font-weight: 700; color: var(--accent); }
47	  .match-head .pname { font-size: 15px; font-weight: 600; }
48	  .kv { display: flex; gap: 12px; flex-wrap: wrap; margin: 6px 0; font-size: 12px; color: var(--muted); }
49	  .rationale { margin: 8px 0; }
50	  .rationale .lbl { font-size: 10px; text-transform: uppercase; color: var(--muted); letter-spacing: .05em; }
51	  details { margin-top: 8px; }
52	  summary { cursor: pointer; color: var(--accent); font-size: 12px; }
53	  pre { white-space: pre-wrap; word-wrap: break-word; background: var(--bg); border: 1px solid var(--border);
54	    border-radius: 6px; padding: 10px; font: 12px/1.5 ui-monospace, Menlo, monospace; margin: 6px 0; max-height: 320px; overflow: auto; }
55	  .status-ready { color: var(--good); } .status-ranked { color: var(--warn); }
56	  .chips { display: flex; gap: 6px; flex-wrap: wrap; margin: 4px 0 2px; }
57	  .subhead { font-size: 10px; text-transform: uppercase; letter-spacing: .05em; color: var(--muted);
58	    margin: 14px 0 6px; font-weight: 600; border-top: 1px solid var(--border); padding-top: 10px; }
59	  .fld { display: flex; gap: 8px; align-items: baseline; padding: 3px 0; flex-wrap: wrap; }
60	  .fld .fk { color: var(--muted); min-width: 130px; font-size: 12px; text-transform: capitalize; }
61	  .fld .fv { flex: 1; min-width: 160px; }
62	  .fld.nested { display: block; }
63	  .fld.nested > .fk { display: block; margin-bottom: 2px; }
64	  .nest { border-left: 1px solid var(--border); padding-left: 10px; margin-left: 4px; }
65	  .src { font-size: 10px; color: var(--accent); text-decoration: none; white-space: nowrap; }
66	  .src:hover { text-decoration: underline; }
67	  .conf { font-size: 10px; color: var(--muted); }
68	  .rel { display: flex; gap: 8px; align-items: baseline; padding: 4px 0; border-bottom: 1px solid var(--border); font-size: 12px; }
69	  .rel .rk { color: var(--accent); font-size: 11px; }
70	  .rel .unres { color: var(--muted); font-style: italic; }
71	  .rel .arrow { color: var(--muted); }
72	  a.lnk { color: var(--accent); text-decoration: none; } a.lnk:hover { text-decoration: underline; }
73	  table { width: 100%; border-collapse: collapse; font-size: 12px; }
74	  td, th { text-align: left; padding: 3px 4px; border-bottom: 1px solid var(--border); }
75	  th { color: var(--muted); font-weight: 500; }
76	  .ev { font-size: 12px; padding: 5px 0; border-bottom: 1px solid var(--border); display: flex; gap: 8px; }
77	  .ev .k { font-weight: 600; }
78	  .ev .t { color: var(--muted); margin-left: auto; white-space: nowrap; }
79	  .kind-Verified, .kind-DraftReady { color: var(--good); }
80	  .kind-VerifyRejected, .kind-DraftDeadLettered { color: var(--bad); }
81	  .kind-MatchesRanked, .kind-FilterCompleted { color: var(--accent); }
82	  .empty { color: var(--muted); font-style: italic; padding: 20px 0; }
83	  .dot { display: inline-block; width: 8px; height: 8px; border-radius: 50%; margin-right: 5px; }
84	  .dot.busy { background: var(--warn); } .dot.idle { background: var(--good); }
85	  .dot.dead { background: var(--bad); } .dot.starting { background: var(--accent); }
86	  .costbar { height: 6px; background: var(--accent); border-radius: 3px; }
87	</style>
